('egg_fried_egg_faroese', 'Egg (Fried Egg)', 196, 13.6, 0.8, 15.5, 0.0, 0.8, 100, 65, 'research', ARRAY['egg (fried egg)', 'fried egg', 'spejlæg', 'striktur egg'], 'traditional', NULL, 1, 'FO', 'Fried egg in butter; the classic Faroese breakfast egg preparation. Served sunny-side up or over-easy with bread and often alongside fried potatoes.', TRUE),
('egg_poached_egg_faroese', 'Egg (Poached Egg)', 143, 12.5, 0.7, 9.9, 0.0, 0.7, 100, 55, 'research', ARRAY['egg (poached egg)', 'poached egg', 'pocheret æg'], 'traditional', NULL, 1, 'FO', 'Poached egg served on rye bread or toast; a lighter egg preparation used in modern Faroese brunch dishes in Tórshavn cafes and restaurants.', TRUE),
('eggjakaka_egg_omelette_faroese', 'Eggjakaka (Egg Omelette)', 158, 10.8, 2.5, 12.0, 0.0, 1.5, 150, NULL, 'research', ARRAY['eggjakaka (egg omelette)', 'omelette', 'omelet', 'omelett'], 'traditional', NULL, 1, 'FO', 'Plain butter-cooked omelette; a quick everyday meal in Faroese homes, served with bread. Often filled with cheese, mushrooms, or the leftover vegetables from the previous day''s dinner.', TRUE),
('eggjakaka_vid_spikinu_bacon_and_egg_omelette_faroese', 'Eggjakaka við Spikinu (Bacon and Egg Omelette)', 218, 14.5, 1.5, 17.5, 0.0, 0.8, 150, NULL, 'research', ARRAY['eggjakaka við spikinu (bacon and egg omelette)', 'bacon omelette', 'spegepølse omelette'], 'traditional', NULL, 1, 'FO', 'Omelette filled with crispy bacon or salt pork; a hearty Faroese brunch or supper dish. Salt pork (spik from preserved meats) was traditionally used before fresh bacon became available.', TRUE),
('eggjakaka_vid_osti_cheese_omelette_faroese', 'Eggjakaka við Osti (Cheese Omelette)', 226, 16.0, 2.2, 17.8, 0.0, 1.5, 150, NULL, 'research', ARRAY['eggjakaka við osti (cheese omelette)', 'cheese omelette', 'osteomelet'], 'traditional', NULL, 1, 'FO', 'Cheese-filled omelette made with semi-hard Danish cheese; a popular everyday meal in Faroese households. The melted cheese interior adds richness to the soft egg.', TRUE),
('skadsegg_seabird_eggs_traditional_use_faroese', 'Skadsegg (Seabird Eggs, Traditional Use)', 162, 12.8, 1.2, 12.0, 0.0, 1.2, 60, 60, 'research', ARRAY['skadsegg (seabird eggs, traditional use)', 'seabird eggs', 'guillemot eggs', 'sjøfuglaæg'], 'traditional', NULL, 1, 'FO', 'Seabird eggs (historically from guillemot, puffin, or gannet); historically collected from sea cliffs during spring nesting season. Still consumed by some islanders as a rare seasonal delicacy.', TRUE),
('budingur_bread_pudding_faroese', 'Búðingur (Bread Pudding)', 228, 6.2, 38.0, 6.5, 0.8, 20.0, 150, NULL, 'research', ARRAY['búðingur (bread pudding)', 'bread pudding', 'brødbudding', 'budding'], 'traditional', NULL, 1, 'FO', 'Baked bread pudding made from stale bread, eggs, milk, and sugar; a thrifty Faroese dessert tradition reflecting the island''s resourcefulness with limited food supplies.', TRUE),
('risgreytur_rice_pudding_faroese', 'Rísgreytur (Rice Pudding)', 132, 3.8, 22.5, 3.5, 0.3, 8.5, 200, NULL, 'research', ARRAY['rísgreytur (rice pudding)', 'risgrød', 'rice porridge', 'rismælk'], 'traditional', NULL, 1, 'FO', 'Creamy rice pudding cooked with whole milk, sugar, and vanilla; a beloved Danish-Faroese dessert eaten warm with cinnamon sugar and a knob of butter. Traditional at Christmas.', TRUE),
('risgreytur_vid_rjoma_rice_pudding_with_cream_faroese', 'Rísgreytur við Rjóma (Rice Pudding with Cream)', 171, 3.5, 21.0, 8.0, 0.3, 8.0, 200, NULL, 'research', ARRAY['rísgreytur við rjóma (rice pudding with cream)', 'ris a l''amande', 'cold rice pudding', 'risalamande'], 'traditional', NULL, 1, 'FO', 'Cold rice pudding mixed with whipped cream; the cold version of ris à l''amande, served at Christmas and celebrations in the Faroe Islands with cherry sauce topping.', TRUE),
('havregreytur_oatmeal_porridge_faroese', 'Havregreytur (Oatmeal Porridge)', 68, 2.5, 12.0, 1.5, 1.6, 0.8, 250, NULL, 'research', ARRAY['havregreytur (oatmeal porridge)', 'oatmeal', 'havregrød', 'porridge'], 'traditional', NULL, 1, 'FO', 'Warm oatmeal porridge cooked with water or milk; a traditional Faroese and Nordic breakfast eaten since the 19th century. Often topped with cold milk, brown sugar, or butter.', TRUE),
('byggreytur_barley_porridge_faroese', 'Byggreytur (Barley Porridge)', 83, 2.4, 17.2, 0.6, 1.8, 0.4, 250, NULL, 'research', ARRAY['byggreytur (barley porridge)', 'barley porridge', 'byggrød', 'barley gruel'], 'traditional', NULL, 1, 'FO', 'Traditional barley porridge; historically the staple morning meal in the Faroe Islands before imported oats became widespread. Barley was locally grown on the islands for centuries.', TRUE),
('rugmjol_greytur_rye_flour_porridge_faroese', 'Rúgmjøl Greytur (Rye Flour Porridge)', 87, 2.8, 18.5, 0.8, 3.2, 0.6, 250, NULL, 'research', ARRAY['rúgmjøl greytur (rye flour porridge)', 'rye porridge', 'ruggrød', 'rye mush'], 'traditional', NULL, 1, 'FO', 'Thick rye flour porridge cooked with water; a historical Faroese subsistence food eaten during lean winter months. Dense and nutritious, it was a morning staple for farming families.', TRUE),
('sukur_greytur_semolina_porridge_faroese', 'Súkur Greytur (Semolina Porridge)', 76, 2.5, 14.8, 0.8, 0.5, 3.5, 200, NULL, 'research', ARRAY['súkur greytur (semolina porridge)', 'semolina porridge', 'semulje grød', 'cream of wheat'], 'traditional', NULL, 1, 'FO', 'Smooth semolina porridge sweetened with sugar; a comforting children''s breakfast and dessert in Faroese homes, influenced by Danish ''grød'' traditions.', TRUE),
('granola_vid_jogurt_granola_with_yogurt_faroese', 'Granola við Jógurt (Granola with Yogurt)', 178, 6.2, 27.5, 5.5, 2.5, 11.0, 200, NULL, 'research', ARRAY['granola við jógurt (granola with yogurt)', 'granola bowl', 'granola og yoghurt'], 'bakery', NULL, 1, 'FO', 'Crunchy baked oat granola with yogurt; a trendy modern breakfast in Tórshavn cafes and homes. Reflects the growing health food culture in the Faroe Islands.', TRUE),
('smorrebrod_vid_laks_smoked_salmon_open_sandwich_faroese', 'Smørrebrød við Laks (Smoked Salmon Open Sandwich)', 198, 12.5, 18.5, 8.5, 2.2, 1.5, 120, NULL, 'research', ARRAY['smørrebrød við laks (smoked salmon open sandwich)', 'smoked salmon sandwich', 'laksesmørrebrød', 'open sandwich'], 'traditional', NULL, 1, 'FO', 'Open-faced rye bread sandwich topped with smoked salmon, cream cheese, and dill; a classic Faroese-Danish lunch item. Salmon farming is a major industry in the Faroe Islands.', TRUE),
('smorrebrod_vid_osti_cheese_open_sandwich_faroese', 'Smørrebrød við Osti (Cheese Open Sandwich)', 265, 11.5, 24.0, 13.5, 3.0, 2.0, 120, NULL, 'research', ARRAY['smørrebrød við osti (cheese open sandwich)', 'cheese sandwich', 'ostesmørrebrød'], 'traditional', NULL, 1, 'FO', 'Open-faced rye bread sandwich with sliced hard cheese; the most basic Faroese packed lunch. Traditionally taken to sea by fishermen and to school by children.', TRUE),
('smorrebrod_vid_eggi_egg_open_sandwich_faroese', 'Smørrebrød við Eggi (Egg Open Sandwich)', 230, 10.5, 20.5, 12.0, 2.5, 1.8, 130, NULL, 'research', ARRAY['smørrebrød við eggi (egg open sandwich)', 'egg sandwich', 'æggemad', 'egg smørrebrød'], 'traditional', NULL, 1, 'FO', 'Open-faced rye bread sandwich with sliced boiled egg, mayonnaise, and watercress or chives; a classic Danish-Faroese lunch sandwich served at cafes and homes.', TRUE),
