('sultu_og_rjomi_jam_and_cream_bread_faroese', 'Sultu og Rjómi (Jam and Cream Bread)', 285, 4.8, 45.0, 9.5, 1.5, 22.0, 80, NULL, 'research', ARRAY['sultu og rjómi (jam and cream bread)', 'bread with jam and cream', 'syltetøj og fløde'], 'traditional', NULL, 1, 'FO', 'White bread spread with homemade berry jam and heavy cream; a traditional Faroese treat at coffee gatherings, using local crowberry or bilberry jams.', TRUE),
('havramjol_koka_oatmeal_cookies_faroese', 'Havramjøl Køka (Oatmeal Cookies)', 435, 6.5, 62.0, 18.5, 3.5, 28.0, 40, 15, 'research', ARRAY['havramjøl køka (oatmeal cookies)', 'oatmeal cookies', 'havregryn småkager', 'oat biscuits'], 'bakery', NULL, 1, 'FO', 'Crispy oatmeal cookies baked with butter, sugar, and rolled oats; a popular home-baked treat in Faroese households. Often prepared for church coffee and community gatherings.', TRUE),
