('kokosmakron_coconut_macaroons_faroese', 'Kokosmakrón (Coconut Macaroons)', 414, 5.5, 52.0, 21.5, 5.0, 40.0, 30, 20, 'research', ARRAY['kokosmakrón (coconut macaroons)', 'coconut macaroons', 'kokosmakroner', 'coconut cookies'], 'bakery', NULL, 1, 'FO', 'Soft coconut macaroons baked with desiccated coconut and egg whites; a popular Danish-style cookie made at home in the Faroe Islands for coffee gatherings.', TRUE),
