('karamelbudding_caramel_custard_flan_faroese', 'Karamelbudding (Caramel Custard Flan)', 138, 4.8, 20.0, 4.5, 0.0, 20.0, 150, NULL, 'research', ARRAY['karamelbudding (caramel custard flan)', 'caramel flan', 'crème caramel', 'karamelbudding'], 'dairy', NULL, 1, 'FO', 'Baked caramel custard (crème caramel) with a golden caramel sauce; a French-influenced dessert adopted into Faroese home baking. Typically served at Sunday dinners and special occasions.', TRUE),
('blaberjasulta_wild_bilberry_jam_faroese', 'Bláberjasulta (Wild Bilberry Jam)', 226, 0.5, 56.0, 0.1, 1.5, 54.0, 20, NULL, 'research', ARRAY['bláberjasulta (wild bilberry jam)', 'bilberry jam', 'blueberry jam', 'bláber syltetøj'], 'traditional', NULL, 1, 'FO', 'Homemade jam from wild Faroese bilberries (bláber); foraged on hillsides and moorlands every August. A treasured Faroese preserve spread on bread or served with skyr.', TRUE),
('kreklingasulta_crowberry_jam_faroese', 'Kreklingasulta (Crowberry Jam)', 218, 0.4, 54.5, 0.2, 2.0, 52.0, 20, NULL, 'research', ARRAY['kreklingasulta (crowberry jam)', 'crowberry jam', 'krekling jam', 'black berry jam'], 'traditional', NULL, 1, 'FO', 'Jam from crowberries (Empetrum nigrum), the most abundant wild berry in the Faroe Islands; foraged extensively on the islands'' black moorlands. Dark, rich, and slightly bitter.', TRUE),
('elsurberjasulta_elderberry_jam_faroese', 'Elsurberjasulta (Elderberry Jam)', 220, 0.5, 55.0, 0.1, 2.0, 53.0, 20, NULL, 'research', ARRAY['elsurberjasulta (elderberry jam)', 'elderberry jam', 'hyldebær marmelade'], 'traditional', NULL, 1, 'FO', 'Deep purple elderberry jam made from wild Faroese elderberries; elderberry shrubs grow in sheltered valleys. The berries must be cooked as they are mildly toxic raw.', TRUE),
('jordarberjasulta_strawberry_jam_faroese', 'Jorðarberjasulta (Strawberry Jam)', 245, 0.5, 61.0, 0.1, 0.8, 58.0, 20, NULL, 'research', ARRAY['jorðarberjasulta (strawberry jam)', 'strawberry jam', 'jordbær syltetøj', 'jorðarberja sulta'], 'traditional', NULL, 1, 'FO', 'Strawberry jam made from garden strawberries; strawberries are among the few fruits that ripen in Faroese kitchen gardens during the long summer days. A universal favorite.', TRUE),
('hunangur_faroese_honey_faroese', 'Hunangur (Faroese Honey)', 304, 0.3, 82.4, 0.0, 0.2, 82.1, 15, NULL, 'research', ARRAY['hunangur (faroese honey)', 'honey', 'raw honey', 'heather honey'], 'traditional', NULL, 1, 'FO', 'Raw honey; bees are kept in sheltered valleys of the Faroe Islands. Faroese honey is prized for its unique floral notes from the islands'' diverse wild heather and meadow flowers.', TRUE),
('appilsinumarmeladi_orange_marmalade_faroese', 'Appilsínumarmelaði (Orange Marmalade)', 246, 0.4, 61.5, 0.1, 0.8, 58.5, 20, NULL, 'research', ARRAY['appilsínumarmelaði (orange marmalade)', 'orange marmalade', 'appelsinsyltetøj', 'marmalade'], 'traditional', NULL, 1, 'FO', 'Orange marmalade imported from Denmark or the UK; a standard Faroese breakfast spread since the mid-20th century. Particularly popular on white toast at morning breakfast.', TRUE),
('mjolkusupan_milk_soup_faroese', 'Mjólkusúpan (Milk Soup)', 72, 3.5, 10.5, 1.8, 0.5, 5.5, 300, NULL, 'research', ARRAY['mjólkusúpan (milk soup)', 'milk soup', 'mælkesuppe', 'sweet milk porridge'], 'traditional', NULL, 1, 'FO', 'Simple warm milk soup with bread or porridge; a traditional Faroese children''s meal and invalid food. Made by heating milk with sugar and vanilla, thickened slightly with flour.', TRUE),
('fiskasupan_classic_fish_soup_faroese', 'Fiskasúpan (Classic Fish Soup)', 85, 8.5, 7.2, 2.8, 0.8, 1.5, 300, NULL, 'research', ARRAY['fiskasúpan (classic fish soup)', 'fish soup', 'fiskesuppe', 'fiskasúpa'], 'traditional', NULL, 1, 'FO', 'Clear or cream-based fish soup with root vegetables; a cornerstone of Faroese everyday cooking. Made with local cod, haddock, or saithe and flavored with parsley and bay leaf.', TRUE),
('seydasupan_lamb_broth_with_vegetables_faroese', 'Seyðasúpan (Lamb Broth with Vegetables)', 65, 6.8, 6.5, 1.8, 1.0, 1.2, 300, NULL, 'research', ARRAY['seyðasúpan (lamb broth with vegetables)', 'lamb broth', 'lammekødsuppe', 'seyðasúpa'], 'traditional', NULL, 1, 'FO', 'Traditional Faroese lamb broth made from simmering lamb bones with root vegetables; a restorative soup eaten on cold days. The broth from cooking ræstkjøt has a particularly intense flavor.', TRUE),
('rjomasupan_vid_seld_cream_of_celery_soup_faroese', 'Rjómasúpan við Seld (Cream of Celery Soup)', 68, 1.5, 7.2, 3.8, 1.2, 2.5, 300, NULL, 'research', ARRAY['rjómasúpan við seld (cream of celery soup)', 'cream of celery', 'sellerisuppe', 'creamy celery soup'], 'traditional', NULL, 1, 'FO', 'Creamy celery and celeriac soup; made during autumn harvest season in Faroese households. Blended smooth and enriched with cream, served with crusty bread.', TRUE),
('fiskibollur_fried_fish_balls_faroese', 'Fiskibollur (Fried Fish Balls)', 185, 13.5, 10.0, 9.5, 0.4, 0.8, 150, 25, 'research', ARRAY['fiskibollur (fried fish balls)', 'fried fish balls', 'stegte fiskeboller', 'fiskifarsur'], 'traditional', NULL, 1, 'FO', 'Pan-fried fish balls made from ground white fish; a popular side dish and light meal in Faroese homes. Served with boiled potatoes and a mustard cream sauce.', TRUE),
('saltfiskur_sodin_boiled_salt_cod_faroese', 'Saltfiskur soðin (Boiled Salt Cod)', 98, 22.0, 0.0, 0.8, 0.0, 0.0, 200, NULL, 'research', ARRAY['saltfiskur soðin (boiled salt cod)', 'boiled salt cod', 'kogt saltfisk', 'bacalao boiled'], 'traditional', NULL, 1, 'FO', 'Desalted and boiled salt cod; a Faroese staple eaten with boiled potatoes, carrots, and mustard sauce. Salt-preserved cod has been the essential protein source in the Faroese diet for centuries.', TRUE),
('turradur_fiskur_sodin_boiled_wind_dried_fish_faroese', 'Turraður Fiskur soðin (Boiled Wind-Dried Fish)', 132, 28.5, 0.0, 1.5, 0.0, 0.0, 180, NULL, 'research', ARRAY['turraður fiskur soðin (boiled wind-dried fish)', 'wind-dried fish boiled', 'tørrfisk kokt', 'turrur fiskur'], 'traditional', NULL, 1, 'FO', 'Rehydrated and boiled wind-dried fish (turrur fiskur); less fermented than ræstur fiskur, with a milder flavor. A traditional Faroese everyday meal paired with potatoes and butter.', TRUE),
('fiskakottur_fish_cake_fishcake_faroese', 'Fiskakøttur (Fish Cake / Fishcake)', 165, 12.0, 12.0, 7.5, 0.5, 1.0, 100, 80, 'research', ARRAY['fiskakøttur (fish cake / fishcake)', 'fish cakes', 'fiskekager', 'fishcakes'], 'traditional', NULL, 1, 'FO', 'Pan-fried Faroese fish cakes made from minced white fish, onion, and potato flour; a classic family meal served with remoulade and pickled cucumber. Found in every Faroese supermarket.', TRUE),
('hvitsosa_white_bechamel_sauce_faroese', 'Hvítsósa (White Bechamel Sauce)', 98, 3.5, 9.5, 5.5, 0.2, 2.8, 100, NULL, 'research', ARRAY['hvítsósa (white bechamel sauce)', 'bechamel', 'white sauce', 'hvítsósa'], 'traditional', NULL, 1, 'FO', 'Classic white béchamel sauce made from butter, flour, and milk; the base sauce for Faroese fish dishes, cauliflower gratin, and lasagne. Central to Faroese home cooking.', TRUE),
('mustard_sosa_mustard_sauce_faroese', 'Mustard Sósa (Mustard Sauce)', 115, 2.5, 8.5, 8.0, 0.5, 4.0, 60, NULL, 'research', ARRAY['mustard sósa (mustard sauce)', 'mustard cream sauce', 'sennepssauce', 'sinnepssósa'], 'traditional', NULL, 1, 'FO', 'Creamy mustard sauce made with Dijon mustard, cream, and a little sugar; the traditional Faroese accompaniment to boiled salt cod and wind-dried fish. Also served with boiled potatoes.', TRUE),
('remoulade_faroese', 'Remoulade', 285, 1.5, 14.5, 25.0, 1.0, 8.5, 30, NULL, 'research', ARRAY['remoulade', 'danish remoulade', 'remouladesauce'], 'traditional', NULL, 1, 'FO', 'Danish-style remoulade sauce with pickled vegetables and capers; the standard Faroese condiment for fish cakes, fried fish, and open-faced sandwiches. Imported from Denmark or homemade.', TRUE),
('mayonnes_mayonnaise_faroese', 'Mayonnes (Mayonnaise)', 680, 1.0, 2.0, 75.0, 0.0, 1.5, 15, NULL, 'research', ARRAY['mayonnes (mayonnaise)', 'mayonnaise', 'mayo', 'hjemmelavet mayonnaise'], 'traditional', NULL, 1, 'FO', 'Rich egg-yolk mayonnaise; used extensively in Faroese salads, sandwich spreads, and as a condiment for fish dishes. Homemade mayonnaise is a point of pride at Faroese festive gatherings.', TRUE),
('persillubutter_parsley_butter_faroese', 'Persillubutter (Parsley Butter)', 695, 1.2, 1.0, 77.0, 0.2, 0.2, 15, NULL, 'research', ARRAY['persillubutter (parsley butter)', 'parsley butter', 'persillesmør', 'herb butter'], 'traditional', NULL, 1, 'FO', 'Compound butter blended with fresh parsley and lemon; melted over grilled fish and boiled vegetables in Faroese cooking. The herb gardens of the Faroe Islands supply fresh parsley.', TRUE),
('gravy_lamb_roast_gravy_faroese', 'Gravy (Lamb Roast Gravy)', 62, 3.2, 5.8, 2.8, 0.2, 0.5, 80, NULL, 'research', ARRAY['gravy (lamb roast gravy)', 'lamb gravy', 'brun sovs', 'kjøtsósa'], 'traditional', NULL, 1, 'FO', 'Rich brown gravy made from roasted lamb drippings, thickened with flour; an essential component of the traditional Faroese Sunday roast. Poured over sliced lamb, potatoes, and vegetables.', TRUE),
('horseradish_krem_horseradish_cream_faroese', 'Horseradish Krem (Horseradish Cream)', 118, 1.5, 8.5, 8.8, 1.2, 4.5, 30, NULL, 'research', ARRAY['horseradish krem (horseradish cream)', 'horseradish cream', 'peberrodscreme', 'hvassrót krem'], 'traditional', NULL, 1, 'FO', 'Freshly grated horseradish blended into whipped cream; served as a condiment with boiled beef, cured fish, and beetroot in traditional Faroese-Danish holiday cooking.', TRUE),
('laukasosa_onion_gravy_faroese', 'Laukasósa (Onion Gravy)', 58, 1.5, 7.8, 2.5, 0.8, 3.5, 80, NULL, 'research', ARRAY['laukasósa (onion gravy)', 'onion gravy', 'løgsovs', 'onion sauce'], 'traditional', NULL, 1, 'FO', 'Sweet caramelized onion gravy served with pork dishes and sausages in Faroese households; made by long-cooking sliced onions until golden and sweet, then adding stock.', TRUE),
('tyttiberjasosa_lingonberry_sauce_faroese', 'Tyttiberjasósa (Lingonberry Sauce)', 94, 0.4, 23.5, 0.1, 2.0, 20.0, 40, NULL, 'research', ARRAY['tyttiberjasósa (lingonberry sauce)', 'lingonberry sauce', 'tyttebærsauce', 'lingon sauce'], 'traditional', NULL, 1, 'FO', 'Sweet-tart lingonberry sauce made from imported or semi-wild berries; served with game, meatballs, and lamb in Faroese cooking, reflecting Scandinavian culinary traditions.', TRUE),
('fiskasalat_fish_paste_salad_faroese', 'Fiskasalat (Fish Paste Salad)', 158, 10.5, 4.5, 11.0, 0.5, 1.5, 100, NULL, 'research', ARRAY['fiskasalat (fish paste salad)', 'fish salad spread', 'fiskesalat', 'fish paste'], 'traditional', NULL, 1, 'FO', 'Creamy fish paste salad made from flaked cooked cod or mackerel blended with mayonnaise and dill; a traditional Faroese sandwich spread for open-faced rye bread.', TRUE),
('raekjusalat_shrimp_salad_faroese', 'Rækjusalat (Shrimp Salad)', 148, 10.5, 5.0, 9.8, 0.5, 2.5, 100, NULL, 'research', ARRAY['rækjusalat (shrimp salad)', 'shrimp salad', 'rejsalat', 'prawn cocktail style'], 'traditional', NULL, 1, 'FO', 'Chilled shrimp mixed with mayonnaise, lemon, and dill; a popular topping for open-faced sandwiches and starter course at Faroese celebrations. North Atlantic shrimp are highly prized.', TRUE),
('selssteinbitar_seal_liver_traditional_faroese', 'Selssteinbítar (Seal Liver, Traditional)', 135, 22.0, 3.5, 4.5, 0.0, 0.0, 100, NULL, 'research', ARRAY['selssteinbítar (seal liver, traditional)', 'seal liver', 'sælelever', 'selur lifur'], 'traditional', NULL, 1, 'FO', 'Pan-fried seal liver; historically consumed by Faroese hunters who traditionally caught seals for food and oil. The liver was prized as the most nutritious part of the animal.', TRUE),
('lambakjot_sodid_boiled_lamb_faroese', 'Lambakjøt soðið (Boiled Lamb)', 168, 25.5, 0.0, 7.5, 0.0, 0.0, 200, NULL, 'research', ARRAY['lambakjøt soðið (boiled lamb)', 'boiled lamb', 'kogt lammekød', 'seyðakjøt soðið'], 'traditional', NULL, 1, 'FO', 'Boiled Faroese lamb; the simplest and most traditional preparation of lamb meat on the islands. Boiled slowly with root vegetables and served with the resulting broth as soup.', TRUE),
