('pylsa_hot_dog_sausage_faroese', 'Pylsa (Hot Dog / Sausage)', 290, 11.5, 22.5, 17.5, 1.0, 5.0, 150, NULL, 'research', ARRAY['pylsa (hot dog / sausage)', 'hot dog', 'rød pølse', 'sausage in bun'], 'traditional', NULL, 1, 'FO', 'Danish-style hot dog (red sausage in a bun with remoulade, fried onions, and pickles); a beloved fast food in the Faroe Islands. Hot dog stands are found throughout Tórshavn.', TRUE),
('koftufar_meatballs_faroese', 'Kóftufar (Meatballs)', 196, 14.5, 8.5, 12.5, 0.5, 1.5, 150, 25, 'research', ARRAY['kóftufar (meatballs)', 'meatballs', 'frikadeller', 'kødboller'], 'traditional', NULL, 1, 'FO', 'Faroese-Danish style meatballs (frikadeller) made from minced pork and veal, pan-fried in butter; a universally loved dish served with boiled potatoes, gravy, and red cabbage.', TRUE),
